import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"17. Types Of Employment","description":"","frontmatter":{"title":"17. Types Of Employment","eba":"Allied Health Professionals 2021-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/allied-health/employment/17-types-of-employment.md","filePath":"ebas/allied-health/employment/17-types-of-employment.md"}'),l={name:"ebas/allied-health/employment/17-types-of-employment.md"};function s(r,e,i,p,h,m){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_17-types-of-employment" tabindex="-1">17. Types Of Employment <a class="header-anchor" href="#_17-types-of-employment" aria-label="Permalink to &quot;17. Types Of Employment&quot;">​</a></h1><p><strong>17.1</strong> Employees under this Agreement may be employed in any one (1) of the following categories:</p><p><strong>(a)</strong> full-time employment (<a href="/eba/ebas/allied-health/employment/18-full-time-employment.html">clause 18</a>);</p><p><strong>(b)</strong> part-time employment (<a href="/eba/ebas/allied-health/employment/19-part-time-employment.html">clause 19</a>);</p><p><strong>(c)</strong> fixed term employment (<a href="/eba/ebas/allied-health/employment/22-fixed-term-employment.html">clause 22</a>); or</p><p><strong>(d)</strong> casual employment (<a href="/eba/ebas/allied-health/employment/20-casual-employment.html">clause 20</a>).</p><p><strong>17.2</strong> At the time of engagement the Employer will inform each Employee of the terms of their engagement, and in particular, whether they are to be full-time, part-time, fixed term or casual Employees.</p><p><strong>17.3</strong> The Employer will give preference to ongoing forms of employment over casual and fixed term employment wherever possible.</p><p><strong>17.4</strong> Where an Employee holds more than one (1) position covered by this Agreement with an Employer:</p><p><strong>(a)</strong> the Employee (or representative) may, where they believe that having regard for the circumstances, the positions could be consolidated into a single position, request that this occur and the Employer can only refuse on reasonable business grounds;</p><p><strong>(b)</strong> the Employer will ensure that the EFT of all the positions combined is no more than 1.0;</p><p><strong>(c)</strong> the terms of:</p><p><strong>(i)</strong> <a href="/eba/ebas/allied-health/hours-of-work/47-hours-of-work.html">Clause 47</a> – Hours of Work;</p><p><strong>(ii)</strong> <a href="/eba/ebas/allied-health/hours-of-work/48-accrued-days-off.html">Clause 48</a> – Accrued Days Off;</p><p><strong>(iii)</strong> <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">Clause 52</a> – Overtime; shall apply to the Employee’s employment with the Employer as though the positions were one (1) position. This includes the limits for ordinary hours as provided by subclauses 47.1 and 47.2 (a maximum of eight (8) ordinary hours, or by agreement up to ten (10) ordinary hours, per shift).</p><p><strong>(d)</strong> the positions will be considered one (1) position for the purposes of accrual and access to leave under this Agreement and the NES, and the following :</p><p><strong>(i)</strong> <a href="/eba/ebas/allied-health/wages/32-accident-pay.html">Clause 32</a> – Accident Pay;</p><p><strong>(ii)</strong> <a href="/eba/ebas/allied-health/allowances/36-allowances-related-to-overtime-and-on-call.html">Clause 36.1</a> – Meal Allowance;</p><p><strong>(iii)</strong> <a href="/eba/ebas/allied-health/allowances/34-sole-allowance.html">Clause 34</a> – Sole Allowance;</p><p><strong>(iv)</strong> <a href="/eba/ebas/allied-health/allowances/35-higher-qualifications-allowance.html">Clause 35</a> - Higher Qualifications Allowance.</p><p><strong>17.5</strong> The Employer shall not engage an Employee in more than one (1) position for the purpose of avoiding entitlements under this Agreement.</p><p><strong>17.6</strong> Where an Employee holds more than one (1) position under more than one (1) enterprise agreement but the positions can fall within the scope of the Agreement the Employee (or representative) may, where they believe that the positions could be consolidated into a single position, request that this occur. The Employer can only refuse the request on reasonable business grounds.</p><p><strong>17.7</strong> Where an Employee holds more than one (1) position, including a position under another enterprise agreement, nothing in this clause 17 limits the ability of the Employee to dispute whether that position should be covered by this Agreement.</p>',23)])])}const g=t(l,[["render",s]]);export{y as __pageData,g as default};
